# === signal/windows/struct.CtrlBreak.html ===
PAIRS['signal/windows/struct.CtrlBreak.html'] = [
    (b'<p>Represents a listener which receives \xe2\x80\x9cctrl-break\xe2\x80\x9d notifications sent to the process\r\nvia <code>SetConsoleCtrlHandler</code>.</p>',
     b'<p>\xe4\xbb\xa3\xe8\xa1\xa8\xe4\xb8\x80\xe4\xb8\xaa\xe7\x9b\x91\xe5\x90\xac\xe5\x99\xa8\xef\xbc\x8c\xe7\x94\xa8\xe4\xba\x8e\xe6\x8e\xa5\xe6\x94\xb6\xe9\x80\x9a\xe8\xbf\x87 <code>SetConsoleCtrlHandler</code>\r\n\xe5\x8f\x91\xe9\x80\x92\xe7\xbb\x99\xe8\xbf\x9b\xe7\xa8\x8b\xe7\x9a\x84 \xe2\x80\x9cctrl-break\xe2\x80\x9d \xe9\x80\x9a\xe7\x9f\xa5\xe3\x80\x82</p>'),
    (b'<p>This listener can be turned into a <code>Stream</code> using <a href="https://docs.rs/tokio-stream/latest/tokio_stream/wrappers/struct.CtrlBreakStream.html"><code>CtrlBreakStream</code></a>.</p>',
     b'<p>\xe6\xad\xa4\xe7\x9b\x91\xe5\x90\xac\xe5\x99\xa8\xe5\x8f\xaf\xe4\xbb\xa5\xe9\x80\x9a\xe8\xbf\x87 <a href="https://docs.rs/tokio-stream/latest/tokio_stream/wrappers/struct.CtrlBreakStream.html"><code>CtrlBreakStream</code></a>\r\n\xe8\xbd\xac\xe6\x8d\xa2\xe4\xb8\xba <code>Stream</code>\xe3\x80\x82</p>'),
    # A notification to this process notifies all receivers...
    (b'<p>A notification to this process notifies <em>all</em> receivers for\r\nthis event. Moreover, the notifications <strong>are coalesced</strong> if they aren\xe2\x80\x99t processed\r\nquickly enough. This means that if two notifications are received back-to-back,\r\nthen the listener may only receive one item about the two notifications.</p>',
     b'<p>\xe5\xaf\xb9\xe8\xbf\x9b\xe7\xa8\x8b\xe7\x9a\x84\xe9\x80\x9a\xe7\x9f\xa5\xe4\xbc\x9a\xe9\x80\x9a\xe7\x9f\xa5<em>\xe6\x89\x80\xe6\x9c\x89</em>\xe7\x9b\x91\xe5\x90\xac\xe8\xaf\xa5\xe4\xba\x8b\xe4\xbb\xb6\xe7\x9a\x84\xe6\x8e\xa5\xe6\x94\xb6\xe8\x80\x85\xe3\x80\x82\r\n\xe6\xad\xa4\xe5\xa4\x96\xef\xbc\x8c\xe5\xa6\x82\xe6\x9e\x9c\xe9\x80\x9a\xe7\x9f\xa5\xe6\xb2\xa1\xe6\x9c\x89\xe8\xa2\xab\xe8\xbf\x9f\xe9\x80\x9f\xe5\xa4\x84\xe7\x90\x86\xef\xbc\x8c\xe9\x82\xa3\xe4\xb9\x88\xe5\xae\x83\xe4\xbb\xac\xe4\xbc\x9a<strong>\xe8\xa2\xab\xe5\x90\x88\xe5\xb9\xb6</strong>\xe3\x80\x82\r\n\xe8\xbf\x99\xe6\x84\x8f\xe5\x91\xb3\xe7\x9d\x80\xe5\xa6\x82\xe6\x9e\x9c\xe8\xbf\x9e\xe7\xbb\xad\xe6\x8e\xa5\xe6\x94\xb6\xe5\x88\xb0\xe4\xb8\xa4\xe4\xb8\xaa\xe9\x80\x9a\xe7\x9f\xa5\xef\xbc\x8c\r\n\xe5\x88\x99\xe7\x9b\x91\xe5\x90\xac\xe5\x99\xa8\xe5\x8f\xaa\xe4\xbc\x9a\xe6\x94\xb6\xe5\x88\xb0\xe4\xb8\x80\xe4\xb8\xaa\xe5\x8c\x85\xe5\x90\xab\xe8\xbf\x99\xe4\xb8\xa4\xe4\xb8\xaa\xe9\x80\x9a\xe7\x9f\xa5\xe7\x9a\x84\xe9\xa1\xb9\xe7\x9b\xae\xe3\x80\x82</p>'),
    (b'<p>Receives the next signal notification event.</p>',
     b'<p>\xe6\x8e\xa5\xe6\x94\xb6\xe4\xb8\x8b\xe4\xb8\x80\xe4\xb8\xaa\xe4\xbf\xa1\xe5\x8f\xb7\xe9\x80\x9a\xe7\x9f\xa5\xe4\xba\x8b\xe4\xbb\xb6\xe3\x80\x82</p>'),
    (b'<p>Although this returns <code>Option&lt;()&gt;</code>, it will never actually return <code>None</code>.\r\nThis was accidentally exposed and would be a breaking change to be removed.</p>',
     b'<p>\xe8\x99\xbd\xe7\x84\xb6\xe8\xbf\x94\xe5\x9b\x9e <code>Option&lt;()&gt;</code>\xef\xbc\x8c\xe4\xbd\x86\xe5\xae\x83\xe4\xbb\x8d\xe7\x84\xb6\xe4\xb8\x8d\xe4\xbc\x9a\xe5\xae\x9e\xe9\x99\x85\xe8\xbf\x94\xe5\x9b\x9e <code>None</code>\xe3\x80\x82\r\n\xe8\xbf\x99\xe6\x98\xaf\xe4\xb8\x80\xe4\xb8\xaa\xe9\x9a\x8f\xe6\x9c\xba\xe5\xb0\xb1\xe6\x9a\x82\xe5\xbc\x80\xe6\x96\xb0\xe7\x9a\x84\xef\xbc\x8c\xe5\x8e\xbb\xe6\x8e\x89\xe5\xae\x83\xe4\xbc\x9a\xe6\x98\xaf\xe4\xb8\xaa\xe7\xa0\xb4\xe5\x9d\x8f\xe6\x80\xa7\xe5\x8f\x98\xe6\x9b\xb4\xe3\x80\x82</p>'),
    (b'<p>Polls to receive the next signal notification event, outside of an\r\n<code>async</code> context.</p>',
     b'<p>\xe5\x9c\xa8 <code>async</code> \xe4\xb8\x8a\xe4\xb8\x8b\xe6\x96\x87\xe4\xb8\xad\xe8\xbd\xae\xe8\xaf\xa2\xe6\x8e\xa5\xe6\x94\xb6\xe4\xb8\x8b\xe4\xb8\x80\xe4\xb8\xaa\xe4\xbf\xa1\xe5\x8f\xb7\xe9\x80\x9a\xe7\x9f\xa5\xe4\xba\x8b\xe4\xbb\xb6\xe3\x80\x82</p>'),
    (b'<p>Polling from a manually implemented future</p>',
     b'<p>\xe4\xbb\x8e\xe6\x89\x8b\xe5\x8a\xa8\xe5\xae\x9e\xe7\x8e\xb0\xe7\x9a\x84 future \xe4\xb8\xad\xe8\xbd\xae\xe8\xaf\xa2</p>'),
]


